def retry(max_attempts=3):
    def decorator(func):
        @functools.wraps(func)  # decorator call: functools.wraps
        def wrapper(*args, **kwargs):
            for i in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception:
                    pass
        return wrapper
    return decorator

